# 1. CI runner policy: read CI secrets only, never prod
vault policy write claude-ci - <<'EOF'
# Eval pipeline and integration tests — CI Claude API key only
path "secret/data/ci/claude/*" {
  capabilities = ["read"]
}
# Dynamic DB credentials for integration tests
path "database/creds/ci-test-role" {
  capabilities = ["read"]
}
# Explicitly deny prod paths (belt-and-suspenders)
path "secret/data/prod/*" {
  capabilities = ["deny"]
}
EOF

# 2. Production app pod policy: read prod secrets only
vault policy write claude-prod-app - <<'EOF'
path "secret/data/prod/claude/api_key" {
  capabilities = ["read"]
}
path "secret/data/prod/claude/webhook_secret" {
  capabilities = ["read"]
}
path "database/creds/prod-role" {
  capabilities = ["read"]
}
EOF

# 3. Developer policy: read dev secrets, no prod/ci write access
vault policy write claude-dev - <<'EOF'
path "secret/data/dev/claude/*" {
  capabilities = ["read", "list"]
}
# Developers can read (but not write) staging for debugging
path "secret/data/staging/claude/*" {
  capabilities = ["read"]
}
EOF

# 4. Admin break-glass policy: full access with audit requirement
vault policy write claude-admin - <<'EOF'
path "secret/*" {
  capabilities = ["create", "read", "update", "delete", "list"]
}
path "auth/*" {
  capabilities = ["create", "read", "update", "delete", "list", "sudo"]
}
path "sys/*" {
  capabilities = ["create", "read", "update", "delete", "list", "sudo"]
}
EOF

#!/usr/bin/env python3
"""audit_vault_access.py — compare live Vault policies to declared matrix."""
import os, sys, yaml, subprocess, json

MATRIX_FILE = "access-matrix.yml"
VAULT_ADDR  = os.environ["VAULT_ADDR"]
VAULT_TOKEN = os.environ["VAULT_TOKEN"]  # admin token for audit

def vault(cmd: list[str]) -> dict:
    result = subprocess.run(
        ["vault"] + cmd + ["-format=json"],
        env={**os.environ, "VAULT_ADDR": VAULT_ADDR, "VAULT_TOKEN": VAULT_TOKEN},
        capture_output=True, text=True
    )
    return json.loads(result.stdout)

def check_capabilities(policy_name: str, path: str) -> list[str]:
    """Return the actual capabilities a policy grants on a path."""
    data = vault(["policy", "read", policy_name])
    # Parse HCL policy — simplified: look for the path block
    # In production, use the Vault sys/capabilities-self endpoint instead
    result = subprocess.run(
        ["vault", "token", "capabilities", path],
        env={**os.environ, "VAULT_ADDR": VAULT_ADDR, "VAULT_TOKEN": VAULT_TOKEN},
        capture_output=True, text=True
    )
    caps = result.stdout.strip().split(", ")
    return [c for c in caps if c]

def audit(matrix_file: str) -> list[dict]:
    with open(matrix_file) as f:
        matrix = yaml.safe_load(f)["matrix"]

    findings = []
    for entry in matrix:
        identity = entry["identity"]
        for path_entry in entry["paths"]:
            path = path_entry["path"].replace("*", "test-value")
            declared = set(path_entry["capabilities"])
            actual = set(check_capabilities(identity, path))

            extra = actual - declared
            missing = declared - actual
            if extra:
                findings.append({
                    "type": "excess_access",
                    "identity": identity,
                    "path": path_entry["path"],
                    "extra_caps": list(extra),
                })
            if missing:
                findings.append({
                    "type": "missing_access",
                    "identity": identity,
                    "path": path_entry["path"],
                    "missing_caps": list(missing),
                })
    return findings

if __name__ == "__main__":
    findings = audit(MATRIX_FILE)
    if findings:
        print(f"Access audit: {len(findings)} discrepancy(ies)")
        for f in findings:
            print(f"  [{f['type']}] {f['identity']} on {f['path']}: {f}")
        sys.exit(1)
    print("Access audit: matrix matches live Vault policies")
